mapper.select:
select cp.*, c.name as campus_name, g.name as grade_name, cls.name as class_name, p.real_name as parent_name, t.real_name as teacher_name from child_profile cp left join campus_info c on cp.campus_id = c.id left join grade_info g on cp.grade_id = g.id left join class_info cls on cp.class_id = cls.id left join sys_user p on cp.parent_id = p.id left join sys_user t on cp.teacher_id = t.id
and cp.class_id = #{classId}
and cp.parent_id = #{parentId}
and cp.profile_status = #{profileStatus}
and cp.teacher_id = #{teacherId}
order by cp.id desc

mapper.update:
update child_profile
child_name = #{childName}, gender = #{gender}, birthday = #{birthday}, campus_id = #{campusId}, grade_id = #{gradeId}, class_id = #{classId}, parent_id = #{parentId}, teacher_id = #{teacherId}, allergy_info = #{allergyInfo}, pickup_person = #{pickupPerson}, profile_status = #{profileStatus},
where id = #{id}
